select id, name, description, create_time AS createTime, status from sms_role
and (name like concat('%', #{keyword}, '%') or description like concat('%', #{keyword}, '%'))
order by create_time desc limit #{limit} offset #{offset}

mapper.update:
update sms_role
name = #{name}, description = #{description}, status = #{status},
where id = #{id}

update sms_permission
pid = #{pid}, name = #{name}, value = #{value}, url = #{url}, status = #{status}, create_time = #{createTime}, sort = #{sort}, type = #{type},
where id = #{id}
